parse:
run {
  // Instance 1: No photos exist. The requirement is vacuously true.
  no Photo and everyPhotoIsPostedByOneUser
} for 4 expect 1

run {
  // Instance 2: One user posts one photo.
  one u: User, one p: Photo |
  u.posts = p and everyPhotoIsPostedByOneUser
} for 4 expect 1

run {
  // Instance 3: One user posts two distinct photos.
  one u: User, some disj p1, p2: Photo |
  u.posts = p1 + p2 and everyPhotoIsPostedByOneUser
} for 4 expect 1

run {
  // Instance 4: Two distinct users each post one distinct photo.
  // Assumes these are the only photos to ensure the predicate holds.
  some disj u1, u2: User, disj p1, p2: Photo |
  u1.posts = p1 and u2.posts = p2 and
  (all p: Photo | p = p1 or p = p2) and
  everyPhotoIsPostedByOneUser
} for 4 expect 1

run {
  // Instance 5: Multiple users post multiple photos, with each photo having exactly one poster.
  // Assumes these are the only photos to ensure the predicate holds.
  some disj u1, u2: User, disj p1, p2, p3: Photo |
  u1.posts = p1 + p2 and
  u2.posts = p3 and
  (all p: Photo | p = p1 or p = p2 or p = p3) and
  everyPhotoIsPostedByOneUser
} for 4 expect 1

run {
  // Instance 5: An Ad is posted by both an Influencer and a Regular User.
  one p: Ad, one inf: Influencer, one reg: User - Influencer |
  p in inf.posts and p in reg.posts
} for 4 expect 0

valid:
run {
  // Instance 3: Two photos exist; one is unposted, and the other is multiply posted by two users.
  some p_unposted, p_multiply: Photo, disj u1, u2: User |
  p_unposted != p_multiply and
  no u: User | p_unposted in u.posts and
  p_multiply in u1.posts and p_multiply in u2.posts
} for 4 expect 0

