run {
  some u: User - Influencer {
    u in u.follows // Forces a regular user to violate
  }
  some i: Influencer // Ensures an influencer exists, even if not self-following
  all x: User | x not in x.follows // Contradiction
} for 4 expect 0

consistent:
run {
  some u: User | u in u.follows // This forces a violation of the requirement
  all x: User | x not in x.follows // This is the requirement itself, creating a contradiction
} for 4 expect 0

run {
  some disj u1, u2: User {
    u1 in u1.follows // Forces a violation
    u2 in u1.follows // Additional relation
  }
  all x: User | x not in x.follows // Contradiction
} for 4 expect 0

run {
  some i: Influencer | i in i.follows // Forces a violation by an Influencer
  all x: User | x not in x.follows // Contradiction
} for 4 expect 0

